# Tres tipos de métodos
class Calculadora:
    PI = 3.14159  # Atributo de clase

    def __init__(self, valor):
        self.valor = valor  # De instancia

    # Método de instancia
    def duplicar(self):
        return self.valor * 2

    # Método de clase
    @classmethod
    def area_circulo(cls, radio):
        return cls.PI * radio ** 2

    # Método estático
    @staticmethod
    def es_par(n):
        return n % 2 == 0

# Usar
calc = Calculadora(10)
print(calc.duplicar())  # 20
print(Calculadora.area_circulo(5))  # 78.54
print(Calculadora.es_par(4))  # True

