# Decorador con argumentos
def repetir(veces):
    def decorador(func):
        def wrapper(*args, **kwargs):
            for _ in range(veces):
                resultado = func(*args, **kwargs)
            return resultado
        return wrapper
    return decorador

@repetir(3)
def decir_hola():
    print("Hola")

decir_hola()  # Imprime Hola 3 veces

# Decorador functools.wraps
from functools import wraps

def mi_decorador(func):
    @wraps(func)  # Preserva metadata de la función original
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@mi_decorador
def original():
    """Documentación de la función original"""
    pass

print(original.__name__)  # original, no wrapper
print(original.__doc__)  # Documentación de la función original

